Certainly! Below is an example of Depth-First Search (DFS) implemented in C++. This implementation uses a recursive approach to traverse or search tree or graph data structures.

```cpp
#include <iostream>
#include <vector>
#include <stack>

using namespace std;

// Function to perform DFS on the graph
void DFS(const vector<vector<int>>& graph, int start, vector<bool>& visited) {
    // Mark the current node as visited and print it
    visited[start] = true;
    cout << start << " ";

    // Recur for all the vertices adjacent to this vertex
    for (int neighbor : graph[start]) {
        if (!visited[neighbor]) {
            DFS(graph, neighbor, visited);
        }
    }
}

// Function to perform DFS traversal from a given source vertex
void performDFS(const vector<vector<int>>& graph, int start) {
    // Create a vector to keep track of visited vertices
    vector<bool> visited(graph.size(), false);

    // Call the recursive helper function to print DFS traversal
    DFS(graph, start, visited);
}

int main() {
    // Example graph represented as an adjacency list
    int V = 5; // Number of vertices
    vector<vector<int>> graph(V);

    // Adding edges to the graph
    graph[0] = {1, 2};
    graph[1] = {0, 3, 4};
    graph[2] = {0, 4};
    graph[3] = {1};
    graph[4] = {1, 2};

    // Perform DFS starting from vertex 0
    cout << "DFS traversal starting from vertex 0: ";
    performDFS(graph, 0);

    return 0;
}
```

### Explanation:
1. **Graph Representation**: The graph is represented as an adjacency list using a vector of vectors.
2. **DFS Function**: The `DFS` function takes the graph, the current vertex, and a visited array as parameters. It marks the current vertex as visited and prints it. Then, it recursively visits all unvisited neighbors.
3. **Perform DFS**: The `performDFS` function initializes a visited array with all elements set to false and calls the recursive `DFS` function starting from the given source vertex.
4. **Main Function**: In the `main` function, an example graph is created, and DFS traversal is performed starting from vertex 0.

You can modify the graph representation and the start vertex as needed for your specific use case.
